import React from 'react';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import styles from '../../../../../styles/documentForm.module.css';

type Props = Pick<
  CashVoucherFormViewModel,
  | 'validationErrors'
  | 'bannerClosed'
  | 'bannerExpanded'
  | 'setBannerExpanded'
  | 'setBannerClosed'
  | 'validationBannerId'
  | 'tid'
>;

export const CashVoucherValidationBanner: React.FC<Props> = ({
  validationErrors,
  bannerClosed,
  bannerExpanded,
  setBannerExpanded,
  setBannerClosed,
  validationBannerId,
  tid,
}) => {
  if (validationErrors.length === 0 || bannerClosed) return null;
  return (
    <div
      id={validationBannerId}
      className={styles.errorBanner}
      data-testid={validationBannerId}
      role="alert"
    >
      <div className={styles.errorBannerBody}>
        <div className={styles.errorBannerHeader}>
          <strong>{validationErrors.length} lỗi cần xử lý</strong>
          <div className={styles.errorBannerActions}>
            <button
              type="button"
              className={styles.errorBannerToggle}
              onClick={() => setBannerExpanded(v => !v)}
            >
              {bannerExpanded ? '▲ Thu gọn' : '▼ Chi tiết'}
            </button>
            <button
              type="button"
              className={styles.errorBannerClose}
              onClick={() => setBannerClosed(true)}
            >
              ✕
            </button>
          </div>
        </div>
        {bannerExpanded && (
          <ul className={styles.errorList}>
            {validationErrors.map((e, i) => (
              <li key={i} data-testid={tid(`validation-error-${i}`)}>{e}</li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};
