import { useCallback } from 'react';
import { validateVoucherDateAgainstPeriods } from '../../../../../utils/accountingPeriodDateValidation';
import {
  scrollToFirstVoucherFieldError,
  validateVoucherFields,
  type VoucherFieldErrors,
} from '../../../../../utils/voucherFieldValidation';
import type { AccountingPeriodGate } from '../../../../../utils/voucherToolbarActions';
import { headerModelFromFields, linesModelsFromState } from '../reducer/fieldHelpers';
import type { CashVoucherFormAction, CashVoucherFormReducerState } from '../types/cashVoucherFormState.types';

export function useCashVoucherValidate(params: {
  state: CashVoucherFormReducerState;
  dispatch: React.Dispatch<CashVoucherFormAction>;
  cashLabel: string;
  partnerLabel: string;
  requireCustomerId: boolean;
  tid: (suffix: string) => string;
  validationBannerId: string;
  processingLevel: string;
  accountingPeriods: AccountingPeriodGate[];
  onProcessingLevelMissing: () => void;
}) {
  const {
    state,
    dispatch,
    cashLabel,
    partnerLabel,
    requireCustomerId,
    tid,
    validationBannerId,
    processingLevel,
    accountingPeriods,
    onProcessingLevelMissing,
  } = params;

  const run = useCallback((): boolean => {
    const h = headerModelFromFields(state.header);
    const lineModels = linesModelsFromState(state.lines);
    const { fieldErrors: nextFieldErrors, bannerMessages } = validateVoucherFields({
      voucherDate: h.voucherDate,
      customerId: h.customerId,
      requireCustomerId,
      partnerLabel,
      accountCode: h.accountCode,
      description: h.description,
      cashLabel,
      lines: lineModels.map(l => ({ accountCode: l.accountCode, debitAmount: l.debitAmount })),
    });

    if (!processingLevel) {
      onProcessingLevelMissing();
      return false;
    }

    const periodError = validateVoucherDateAgainstPeriods(h.voucherDate, accountingPeriods);
    if (periodError) {
      nextFieldErrors.voucherDate = periodError;
      bannerMessages.push(periodError);
    }

    const general = bannerMessages.filter((m: string) => m === 'Phải có ít nhất 1 dòng định khoản');
    if (bannerMessages.length > 0) {
      dispatch({ type: 'SET_FIELD_ERRORS', fieldErrors: nextFieldErrors, generalErrors: general });
      scrollToFirstVoucherFieldError(nextFieldErrors, tid, validationBannerId);
      return false;
    }

    dispatch({ type: 'CLEAR_VALIDATION' });
    return true;
  }, [state, dispatch, cashLabel, partnerLabel, requireCustomerId, processingLevel, accountingPeriods, onProcessingLevelMissing, tid, validationBannerId]);

  return { run };
}

export function patchFieldErrorsToHeader(
  fieldErrors: VoucherFieldErrors,
  dispatch: React.Dispatch<CashVoucherFormAction>,
) {
  if (fieldErrors.voucherDate) {
    dispatch({ type: 'SET_HEADER_ERROR', key: 'voucherDate', error: fieldErrors.voucherDate });
  }
  if (fieldErrors.customerId) {
    dispatch({ type: 'SET_HEADER_ERROR', key: 'customerId', error: fieldErrors.customerId });
  }
  if (fieldErrors.accountCode) {
    dispatch({ type: 'SET_HEADER_ERROR', key: 'accountCode', error: fieldErrors.accountCode });
  }
  if (fieldErrors.description) {
    dispatch({ type: 'SET_HEADER_ERROR', key: 'description', error: fieldErrors.description });
  }
}
